function findMinArrowShots(points: number[][]): number {
  if (points.length === 0) return 0;
  const arr = points.slice().sort((a, b) => a[1] - b[1]);
  let arrows = 1, end = arr[0][1];
  for (let i = 1; i < arr.length; i++) {
    if (arr[i][0] > end) { arrows++; end = arr[i][1]; }
  }
  return arrows;
}
